// Chunk the document — reads directly from $input (form data)
const item = $input.first();

// Get binary file data
const binaryData = item.binary;
if (!binaryData || Object.keys(binaryData).length === 0) {
  throw new Error('No file uploaded. Please upload a .txt file.');
}

const fileKey = Object.keys(binaryData)[0];
const file = binaryData[fileKey];

// Read file content using n8n's binary buffer helper
const buffer = await this.helpers.getBinaryDataBuffer(0, fileKey);
const docText = buffer.toString('utf-8');

const title = file.fileName?.replace(/\.[^.]+$/, '') || 'Untitled';

if (!docText || docText.length < 10) {
  throw new Error('File is empty or too short. Received ' + docText.length + ' chars.');
}

const CHUNK_SIZE = 500;
const OVERLAP    = 80;
const chunks     = [];
let start        = 0;

while (start < docText.length) {
  let end = Math.min(start + CHUNK_SIZE, docText.length);
  if (end < docText.length) {
    const w = docText.slice(start, end + 80);
    const bp = Math.max(w.lastIndexOf('\n\n'), w.lastIndexOf('. '), w.lastIndexOf('.\n'));
    if (bp > CHUNK_SIZE * 0.4) end = start + bp + 1;
  }
  const text = docText.slice(start, end).trim();
  if (text.length > 20) {
    chunks.push({ text, document_title: title, chunk_index: chunks.length });
  }
  start = Math.max(start + 1, end - OVERLAP);
}

return [{
  json: {
    document_title: title,
    total_chunks: chunks.length,
    chunks,
    chunk_texts: chunks.map(c => c.text)
  }
}];

// Build ChromaDB payload from chunks + embeddings
const chunkData  = $('Chunk Document').first().json;
const embeddings = $input.first().json.data;

const ids = chunkData.chunks.map((_, i) => 
  'doc-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 10) + '-' + i
);
const vectors   = embeddings.map(e => e.embedding);
const documents = chunkData.chunks.map(c => c.text);
const metadatas = chunkData.chunks.map(c => ({
  document_title: c.document_title,
  chunk_index: c.chunk_index,
  ingested_at: new Date().toISOString()
}));

return [{
  json: {
    document_title: chunkData.document_title,
    total_chunks: chunkData.total_chunks,
    collection_id: $('Get Collection ID').first().json.id,
    chroma_body: { ids, embeddings: vectors, documents, metadatas }
  }
}];

const payload = $('Build ChromaDB Payload').first().json;
return [{ json: {
  status: 'success',
  message: 'Document "' + payload.document_title + '" ingested successfully.',
  chunks_stored: payload.total_chunks,
  collection: 'llm04_demo'
}}];

const raw = ($input.first().json.chatInput || '').trim();
return [{ json: {
  user_query: raw || 'What does the Enterprise plan cost and which plan do you recommend for a team of 15?',
  session_id: $input.first().json.sessionId || 'default'
}}];

// Parse ChromaDB results (double-nested arrays)
const raw   = $input.first().json;
const query = $('Parse Query').first().json;

const ids       = raw.ids?.[0]       || [];
const docs      = raw.documents?.[0] || [];
const metas     = raw.metadatas?.[0] || [];
const distances = raw.distances?.[0] || [];

if (ids.length === 0) {
  return [{ json: {
    user_query: query.user_query,
    session_id: query.session_id,
    retrieved_chunks: [],
    context_string: '[No documents found. Ingest at least one document first.]',
    source_documents: []
  }}];
}

const chunks = ids.map((id, i) => ({
  rank: i + 1,
  similarity: +(1 - (distances[i] || 0)).toFixed(3),
  text: docs[i] || '',
  document_title: metas[i]?.document_title || 'Unknown',
  chunk_index: metas[i]?.chunk_index ?? i
}));

const context_string = chunks
  .map(c => '[Source: ' + c.document_title + ' | chunk ' + c.chunk_index + ' | sim: ' + c.similarity + ']\n' + c.text)
  .join('\n\n---\n\n');

return [{ json: {
  user_query: query.user_query,
  session_id: query.session_id,
  retrieved_chunks: chunks,
  context_string,
  source_documents: [...new Set(chunks.map(c => c.document_title))]
}}];

